class Solution {
public:
    string originalDigits(string s) {
        vector<int> count(10, 0);
        vector<string> numStrs = {"zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"};
        vector<string> charStrs = {"z", "w", "t", "u", "x", "s", "o", "f", "v", "h", "n", "i", "r", "e", "g"};
        for (int i = 0; i < 10; i++) {
            for (char c : numStrs[i]) {
                count[i] += countChar(s, c);
            }
        }
        vector<int> res(10, 0);
        for (int i = 0; i < 10; i++) {
            res[i] = count[i];
            for (int j = 0; j < 10; j++) {
                if (i != j && count[j] > 0) {
                    res[i] -= countChar(s, charStrs[j][0]);
                }
            }
        }
        string resStr;
        for (int i = 0; i < 10; i++) {
            while (res[i] > 0) {
                resStr += to_string(i);
                res[i]--;
            }
        }
        return resStr;
    }
    int countChar(string s, char c) {
        int count = 0;
        for (char ch : s) {
            if (ch == c) {
                count++;
            }
        }
        return count;
    }
};
